{
  "name": "flashcard-app",
  "version": "0.1.0",
  "private": true,
  "description": "Minimal Express server base for flash card app",
  "scripts": {
    "start": "node server.js",
    "dev": "nodemon server.js",
    "test": "jest --runInBand"
  },
  "dependencies": {
    "express": "^4.19.2"
  },
  "devDependencies": {
    "jest": "^29.7.0",
    "supertest": "^6.3.4",
    "nodemon": "^3.1.0"
  },
  "jest": {
    "testEnvironment": "node"
  }
}

const app = require('./app');

const PORT = process.env.PORT || 7995;

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

const express = require('express');
const path = require('path');

const app = express();

// Parse JSON bodies
app.use(express.json());

// Serve static files from public/
const publicDir = path.join(__dirname, 'public');
app.use(express.static(publicDir));

// Health check endpoint
app.get('/health', (_req, res) => {
  res.status(200).json({ status: 'ok' });
});

module.exports = app;

document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('addForm');
  const cardFront = document.getElementById('card-front');
  const frontInput = document.getElementById('frontInput');
  const backInput = document.getElementById('backInput');

  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const front = (frontInput && frontInput.value ? frontInput.value : '').trim();
      const back = (backInput && backInput.value ? backInput.value : '').trim();
      if (!front || !back) return;
      if (cardFront) cardFront.textContent = front;
      form.reset();
    });
  }

  const flipBtn = document.getElementById('flipBtn');
  if (flipBtn) {
    flipBtn.addEventListener('click', () => {
      if (!cardFront) return;
      cardFront.textContent = cardFront.textContent === 'Back' ? 'Front' : 'Back';
    });
  }
});

const request = require('supertest');
const app = require('../app');

describe('Express base server and frontend', () => {
  it('GET /health returns 200 with {status:"ok"}', async () => {
    const res = await request(app).get('/health');
    expect(res.status).toBe(200);
    expect(res.body).toEqual({ status: 'ok' });
  });

  it('serves public/index.html at / with Tailwind Play CDN present', async () => {
    const res = await request(app).get('/');
    expect(res.status).toBe(200);
    expect(res.text).toMatch(/Flashcard\s+App/i);
    expect(res.text).toMatch(/cdn\.tailwindcss\.com/);
  });

  it('serves public/app.js', async () => {
    const res = await request(app).get('/app.js');
    expect(res.status).toBe(200);
    expect(res.type).toMatch(/javascript/);
  });
});
